sys_script_client.script:
function onChange(control, oldValue, newValue, isLoading, isTemplate) {
    if (isLoading || newValue === '') {
        return;
    }

    // 1. Convert to lowercase and strip underscores/spaces
    // Example: 'itsm_pro' becomes 'itsmpro'
    var input = newValue.toString().toLowerCase().replace(/[^a-z0-9]/g, '');
    var cost = 0;

    // 2. Sequential Matching for all 20 Subcategories
    // ITSM
    if (input.indexOf('itsmstandard') > -1) { cost = 1000; }
    else if (input.indexOf('itsmpro') > -1) { cost = 1200; }
    else if (input.indexOf('itsmenterprise') > -1) { cost = 1500; }
    else if (input.indexOf('itsmadmin') > -1) { cost = 1200; }

    // HRSD
    else if (input.indexOf('hrsdstandard') > -1) { cost = 800; }
    else if (input.indexOf('hrsdpro') > -1) { cost = 1000; }
    else if (input.indexOf('hrsdenterprise') > -1) { cost = 1300; }
    else if (input.indexOf('hrsdadmin') > -1) { cost = 1000; }
    else if (input.indexOf('hrsder') > -1) { cost = 1100; }

    // CSM
    else if (input.indexOf('csmstandard') > -1) { cost = 900; }
    else if (input.indexOf('csmpro') > -1) { cost = 1100; }
    else if (input.indexOf('csmenterprise') > -1) { cost = 1400; }
    else if (input.indexOf('csmadmin') > -1) { cost = 1100; }
    else if (input.indexOf('csmcontributor') > -1) { cost = 500; }

    // SPM
    else if (input.indexOf('spmstandard') > -1) { cost = 1100; }
    else if (input.indexOf('spmpro') > -1) { cost = 1300; }
    else if (input.indexOf('spmenterprise') > -1) { cost = 1600; }
    else if (input.indexOf('spmadmin') > -1) { cost = 1300; }
    else if (input.indexOf('spmagile') > -1) { cost = 400; }

    // Global & Others
    else if (input.indexOf('approveruser') > -1) { cost = 100; }
    else if (input.indexOf('stakeholder') > -1) { cost = 300; }
    else if (input.indexOf('appengine') > -1) { cost = 800; }

    // 3. Update the form UI
    g_form.setValue('amount', cost.toString());
}
